\bigl(f \cdot g\bigr)'(x)
&= \lim_{h \to 0}
   \frac{f(x+h)\,g(x+h) - f(x)\,g(x)}{h} \\[4pt]
&= \lim_{h \to 0}
   \frac{f(x+h)\,g(x+h) - f(x)\,g(x+h)
         + f(x)\,g(x+h) - f(x)\,g(x)}{h} \\[4pt]
&= \lim_{h \to 0}
   \frac{f(x+h) - f(x)}{h}\cdot g(x+h)
   \;+\;
   f(x)\cdot \lim_{h \to 0}
   \frac{g(x+h) - g(x)}{h}.
\end{align*}

